mapper.select:
SELECT DISTINCT t.code
FROM (
    SELECT pc.code
    FROM base_data_product_sku_code pc
    JOIN base_data_product_sku s ON s.id = pc.sku_id AND s.available = TRUE
    JOIN base_data_product p ON p.id = s.product_id AND p.available = TRUE
    WHERE pc.code IN

        #{item}


        AND s.product_id != #{productId}


        AND pc.sku_id != #{skuId}

    UNION ALL
    SELECT p.code
    FROM base_data_product p
    WHERE p.available = TRUE
      AND p.code IN

        #{item}


        AND p.id != #{productId}

) t
